#include<stdio.h>
double power(double x, int p);
void main() {
    double x;
    int p;
    for(x=2.0; x<=5.0; x++)
        for(p=0; p<5; p++)
            printf("%.2lf raised to %d = %.2lf\n", x, p, power(x,p));
}
double power(double x, int p) {
    if(p==0) return 1;
    else if(p>0) {
        double result=1;
        for(int i=0;i<p;i++) result *= x;
        return result;
    } else {
        double result=1;
        for(int i=0;i<-p;i++) result /= x;
        return result;
    }
}

