Switch statement allows a program to select one statement for execution out of a set of alternatives. Only one case executes based on expression value.

Example:
#include<stdio.h>
void main() {
    int num1,num2,result;
    char operator;
    printf("Enter two numbers: ");
    scanf("%d%d",&num1,&num2);
    printf("Enter operator: ");
    scanf(" %c",&operator);
    switch(operator) {
        case '+': result = num1+num2; break;
        case '-': result = num1-num2; break;
        case '*': result = num1*num2; break;
        default: printf("Unknown operator"); result=0;
    }
    printf("%d",result);
}

